String reverseWords(String s) {
    String[] words = s.split(" ");
    String result = "";
    for (String word : words) {
        StringBuilder reversedWord = new StringBuilder(word);
        result += reversedWord.reverse().toString() + " ";
    }
    return result.trim();
}

